type PriorityQueue struct {
    elements []pair
}

type pair struct {
    time  int64
    node  int64
}

func (pq *PriorityQueue) Push(x interface{}) {
    e := x.(pair)
    pq.elements = append(pq.elements, e)
}

func (pq *PriorityQueue) Pop() interface{} {
    old := pq.elements
    n := len(old)
    if n == 0 {
        return pair{}
    }
    res := old[n-1]
    pq.elements = old[0 : n-1]
    return res
}

func (pq *PriorityQueue) Len() int {
    return len(pq.elements)
}

func (pq *PriorityQueue) Less(i, j int) bool {
    return pq.elements[i].time < pq.elements[j].time
}

func (pq *PriorityQueue) Swap(i, j int) {
    pq.elements[i], pq.elements[j] = pq.elements[j], pq.elements[i]
}

func solve(n int64, edges [][]int64) int64 {
