    adj := make(map[int64][]pair)
    for _, edge := range edges {
        u := edge[0]
        v := edge[1]
        start := edge[2]
        end := edge[3]
        adj[u] = append(adj[u], pair{v, start, end})
    }

    // Dijkstra's algorithm with priority queue
    pq := &PriorityQueue{}
    dist := make([]int64, n)
    for i := range dist {
        dist[i] = 1 << 63 - 1
    }
    dist[0] = 0
    heap.Init(pq)
    heap.Push(pq, pair{0, 0})

    for pq.Len() > 0 {
        current := heap.Pop(pq).(pair)
        time := current.time
        node := current.node

        if node == n-1 {
            return time
        }

        if time > dist[node] {
            continue
        }

        // Try to stay at the current node
        newTime := time + 1
        if newTime < dist[node] {
            dist[node] = newTime
            heap.Push(pq, pair{newTime, node})
        }

        // Try to take each outgoing edge
        for _, edge := range adj[node] {
            v := edge.v
            start := edge.start
            end := edge.end
